public static long solve(long[] nums, long k) {
    int n = nums.length;
    if (n == 0) {
        return -1;
    }

    // 1. Precalculate Suffix Minimums (MinRight_i)
    // suffixMin[i] stores min(nums[i]...nums[n-1])
    long[] suffixMin = new long[n];
    suffixMin[n - 1] = nums[n - 1];
    for (int i = n - 2; i >= 0; i--) {
        suffixMin[i] = Math.min(nums[i], suffixMin[i + 1]);
    }

    // 2. Iterate and check stability condition
    long currentMax = -1; // Since nums[i] >= 0, initializing to -1 ensures the first element sets the max correctly.

    for (int i = 0; i < n; i++) {
        // Update MaxLeft_i
        if (i == 0) {
            currentMax = nums[0];
        } else {
            currentMax = Math.max(currentMax, nums[i]);
        }

        // MinRight_i is precalculated
        long minRight = suffixMin[i];

        // Calculate Unstable Value U_i
        long unstableValue = currentMax - minRight;

        // Check stability condition
        if (unstableValue <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}

